$ErrorActionPreference='Stop';$repo=Split-Path (Split-Path $PSScriptRoot -Parent) -Parent;$checks=[ordered]@{}
$props=[xml](Get-Content "$repo\Directory.Build.props" -Raw);$checks.VersionPrefix=$props.Project.PropertyGroup.VersionPrefix-eq'1.0.0';$checks.AssemblyVersion=$props.Project.PropertyGroup.AssemblyVersion-eq'1.0.0.0';$checks.Locking=$props.Project.PropertyGroup.RestorePackagesWithLockFile-eq'true'
$workflows=Get-ChildItem "$repo\.github\workflows" -Filter *.yml -ErrorAction SilentlyContinue;$raw=($workflows|Get-Content -Raw)-join"`n";$uses=[regex]::Matches($raw,'uses:\s*[^@\s]+@([^\s#]+)')|ForEach-Object{$_.Groups[1].Value};$checks.FullShaActions=@($uses|Where-Object{$_-notmatch'^[0-9a-f]{40}$'}).Count-eq0;$checks.NoPrTarget=$raw-notmatch'pull_request_target';$checks.NoWorkflowDownload=$raw-notmatch'Invoke-WebRequest|curl\s|releases/latest';$checks.MinPermissions=$raw-match'permissions:\s*\r?\n\s+contents:\s*read';$checks.ReleaseRunner=$raw-match'self-hosted[\s\S]*licensescope-release';$checks.ProtectedEnvironment=$raw-match'environment:\s*production-release';$checks.PublishDefault=$raw-match'publish_release:[\s\S]*default:\s*false';$checks.NoPrSecrets=$raw-notmatch'pull_request[\s\S]{0,800}secrets\.'
$builder=Get-Content "$repo\build\Build-ReleaseCandidate.ps1" -Raw;$checks.StableUnsignedRejected=$builder-match'Unsigned stable release rejected';$checks.UnsignedNaming=$builder-match"-unsigned";$checks.SbomParameter=$builder-match'SbomToolPath';$checks.NoHardcodedTool=$builder-notmatch'D:\\Tools\\';$checks.WorkflowRequiresCleanSource=$raw-notmatch'AllowDirtySource';$failed=@($checks.GetEnumerator()|Where-Object{-not$_.Value});if($failed){throw 'Release policy failures: '+($failed.Name-join', ')};Write-Host "ReleasePolicy: $($checks.Count) passed"
